using UnityEngine;

/// <summary>
/// Connects a <see cref="DropTarget"/> to a <see cref="BoardLight"/>.
/// Off/on colors come from <see cref="BoardLight"/> in the Inspector;
/// this component supplies the frenzy lit color (Carolina blue by
/// default) only when frenzy is active (ball entered the portal),
/// not merely when all three targets are down.
/// </summary>
[DefaultExecutionOrder(50)]
public class DropTargetLightBulb : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private DropTarget dropTarget;

    [Tooltip("Board light for bulb mesh + optional point light. Defaults to GetComponent.")]
    [SerializeField] private BoardLight boardLight;

    [Header("Frenzy")]
    [Tooltip("Lit color when frenzy is active (portal entered). Normal lit/unlit uses BoardLight.")]
    [SerializeField] private Color frenzyLitColor = new Color(0.337f, 0.627f, 0.827f, 1f);

    [Tooltip("Assign the DropTargetsScoringMode on the board.")]
    [SerializeField] private DropTargetsScoringMode scoringMode;


    private void Awake()
    {
        if (boardLight == null)
        {
            boardLight = GetComponent<BoardLight>();
        }

        if (dropTarget == null)
        {
            dropTarget = GetComponentInParent<DropTarget>();
        }
    }

    private void OnEnable()
    {
        if (dropTarget != null)
        {
            dropTarget.OnFullyDown += HandleTargetStateChanged;
            dropTarget.OnReturnedUp += HandleTargetStateChanged;
        }

        if (scoringMode != null)
        {
            scoringMode.OnFrenzyActivated += HandleFrenzyStateChanged;
            scoringMode.OnFrenzyDeactivated += HandleFrenzyStateChanged;
        }

        RefreshLightState();
    }

    private void Start()
    {
        RefreshLightState();
    }

    private void OnDisable()
    {
        if (dropTarget != null)
        {
            dropTarget.OnFullyDown -= HandleTargetStateChanged;
            dropTarget.OnReturnedUp -= HandleTargetStateChanged;
        }

        if (scoringMode != null)
        {
            scoringMode.OnFrenzyActivated -= HandleFrenzyStateChanged;
            scoringMode.OnFrenzyDeactivated -= HandleFrenzyStateChanged;
        }
    }

    private void HandleTargetStateChanged()
    {
        RefreshLightState();
    }

    private void HandleFrenzyStateChanged()
    {
        RefreshLightState();
    }

    private void RefreshLightState()
    {
        if (boardLight == null)
        {
            return;
        }

        if (dropTarget == null || !dropTarget.IsDown)
        {
            boardLight.ClearLitAppearanceOverride();
            boardLight.SetLit(false);
            return;
        }

        boardLight.SetLit(true);

        bool frenzy = scoringMode != null
            && scoringMode.IsFrenzyActive;

        if (frenzy)
        {
            boardLight.SetLitAppearanceOverride(frenzyLitColor);
        }
        else
        {
            boardLight.ClearLitAppearanceOverride();
        }
    }
}
